import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './PageStyles.css'; // Inheriting dashboard styling

const AddShipmentHub = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        hubName: '',
        email: '',
        password: '',
        location: '',
        walletAddress: ''
    });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    const connectWallet = async () => {
        if (window.ethereum) {
            try {
                const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
                setFormData({ ...formData, walletAddress: accounts[0] });
                setMessage('Wallet connected successfully!');
            } catch (err) {
                console.error(err);
                setMessage('Wallet connection denied.');
            }
        } else {
            setMessage('MetaMask is not installed.');
        }
    };

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.walletAddress) {
            setMessage('Please connect your MetaMask wallet before saving the Hub.');
            return;
        }

        setLoading(true);
        setMessage('');

        try {
            const payload = {
                username: formData.hubName,
                email: formData.email,
                password: formData.password,
                role: 'SHIPMENT_HUB',
                location: formData.location,
                walletAddress: formData.walletAddress
            };

            await axios.post('http://localhost:8080/api/auth/register', payload);
            setMessage('Shipment Hub successfully registered!');

            setTimeout(() => navigate('/dashboard'), 2000);
        } catch (error) {
            console.error('Registration failed:', error);
            setMessage(error.response?.data?.message || 'Failed to register Hub.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="dashboard-container">
            <h1 className="dashboard-title">Register Shipment Hub</h1>
            <p style={{textAlign: 'center', color: '#94a3b8', marginBottom: '2rem'}}>
                Bind a geographic authority node to the AgriChain network.
            </p>

            {message && (
                <div style={{
                    padding: '1rem', marginBottom: '1.5rem', borderRadius: '8px', textAlign: 'center',
                    background: message.includes('success') ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)',
                    color: message.includes('success') ? '#10b981' : '#f87171',
                    border: `1px solid ${message.includes('success') ? '#10b981' : '#f87171'}`
                }}>
                    {message}
                </div>
            )}

            <form onSubmit={handleSubmit} className="product-form" style={{ maxWidth: '600px', margin: '0 auto' }}>
                <div className="form-group">
                    <label>Hub Name (ID)</label>
                    <input type="text" name="hubName" placeholder="e.g. Mumbai Central Depot" value={formData.hubName} onChange={handleChange} required />
                </div>

                <div className="form-group">
                    <label>Hub Specific Location</label>
                    <input type="text" name="location" placeholder="e.g. Navi Mumbai, Maharashtra" value={formData.location} onChange={handleChange} required />
                </div>

                <div className="form-group">
                    <label>Contact Email</label>
                    <input type="email" name="email" value={formData.email} onChange={handleChange} required />
                </div>

                <div className="form-group">
                    <label>Hub Manager Portal Password</label>
                    <input type="password" name="password" value={formData.password} onChange={handleChange} required />
                </div>

                <div className="form-group">
                    <label>Authority Wallet Binding</label>
                    <div style={{display: 'flex', gap: '1rem'}}>
                        <input 
                            type="text" 
                            name="walletAddress" 
                            value={formData.walletAddress} 
                            placeholder="Connect Wallet to Auto-fill" 
                            readOnly 
                            required 
                            style={{ flex: 1 }}
                        />
                        <button type="button" onClick={connectWallet} className="secondary-button" style={{whiteSpace: 'nowrap'}}>
                            {formData.walletAddress ? 'Connected' : 'Bind Web3 Wallet'}
                        </button>
                    </div>
                </div>

                <button type="submit" className="primary-button" disabled={loading} style={{ width: '100%', marginTop: '1rem' }}>
                    {loading ? 'Registering Hub...' : 'Save Hub & Generate Role'}
                </button>
            </form>
        </div>
    );
};

export default AddShipmentHub;
